mapper.select:
SELECT COUNT(*)
FROM meetings m
WHERE m.deletedAt IS NULL
  AND (
    m.hostUserId = #{userId}
    OR EXISTS (
        SELECT 1
        FROM meetingParticipants mp
        WHERE mp.meetingId = m.meetingId
          AND mp.userId = #{userId}
          AND mp.status = 'APPROVED'
    )
  )
  AND (
    m.hostUserId = #{targetUserId}
    OR EXISTS (
        SELECT 1
        FROM meetingParticipants targetMp
        WHERE targetMp.meetingId = m.meetingId
          AND targetMp.userId = #{targetUserId}
          AND targetMp.status = 'APPROVED'
    )
  )

mapper.insert:
INSERT INTO directChatParticipants(
    roomId,
    userId
)
VALUES(
    #{roomId},
    #{userId}
)

mapper.select:
SELECT userId
FROM directChatParticipants
WHERE roomId = #{roomId}
  AND userId != #{senderUserId}

mapper.update:
UPDATE directChatParticipants
SET leftAt = NOW()
WHERE roomId = #{roomId}
  AND userId = #{userId}

UPDATE directChatRooms
SET isActive = 0,
    updatedAt = NOW()
WHERE roomId = #{roomId}
  AND NOT EXISTS (
      SELECT 1
      FROM directChatParticipants p
      WHERE p.roomId = #{roomId}
        AND p.leftAt IS NULL
  )
